#include <stdio.h>
#include <math.h>
#define PI 3.14159265358979323846

int main() {
    int M, N;
    scanf("%d", &M);
    double x[M], y[M], r[M];
    for (int i = 0; i < M; i++) {
        scanf("%lf %lf %lf", &x[i], &y[i], &r[i]);
    }
    scanf("%d", &N);
    double px[N], py[N];
    for (int i = 0; i < N; i++) {
        scanf("%lf %lf", &px[i], &py[i]);
    }
    double area = 0;
    for (int i = 0; i < N; i++) {
        double x1 = px[i], y1 = py[i];
        double x2 = px[(i + 1) % N], y2 = py[(i + 1) % N];
        for (int j = 0; j < M; j++) {
            double dx = x[j] - x1, dy = y[j] - y1;
            double dist = sqrt(dx * dx + dy * dy);
            if (dist <= r[j]) {
                area += (x1 * y2 - x2 * y1);
            }
        }
    }
    area = fabs(area) / 2;
    printf("%.6f\n", area);
    return 0;
}

