const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];
const M = parseInt(readline());
const X = [], Y = [], R = [];
for (let i = 0; i < M; i++) {
    const [x, y, r] = readline().split(' ').map(Number);
    X.push(x);
    Y.push(y);
    R.push(r);
}
const N = parseInt(readline());
const PX = [], PY = [];
for (let i = 0; i < N; i++) {
    const [px, py] = readline().split(' ').map(Number);
    PX.push(px);
    PY.push(py);
}
let area = 0;
for (let i = 0; i < N; i++) {
    const x1 = PX[i], y1 = PY[i];
    const x2 = PX[(i + 1) % N], y2 = PY[(i + 1) % N];
    for (let j = 0; j < M; j++) {
        const dx = X[j] - x1, dy = Y[j] - y1;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist <= R[j]) {
            area += (x1 * y2 - x2 * y1);
        }
    }
}
